function t(key) {
  return UI_TEXT[state.lang][key] || UI_TEXT.en[key] || key;
}

function isArabic() {
  return state.lang === "ar";
}

function serviceText(service, field) {
  const arabicField = field + "Ar";
  return isArabic() ? service[arabicField] || service[field] || "" : service[field] || "";
}

function serviceListItems(service, field) {
  const arabicField = field + "Ar";
  return isArabic() ? service[arabicField] || service[field] || [] : service[field] || [];
}

function subServiceText(subService, field) {
  if (!subService) return "";
  const arabicField = field + "Ar";
  return isArabic() ? subService[arabicField] || subService[field] || "" : subService[field] || "";
}

function subServiceListItems(subService, field) {
  if (!subService) return [];
  const arabicField = field + "Ar";
  return isArabic() ? subService[arabicField] || subService[field] || [] : subService[field] || [];
}

function getSubServices(service) {
  return service.subServices?.length ? service.subServices : serviceListItems(service, "requirements").map((title, index) => ({
    id: service.id + "-legacy-" + index,
    title,
    titleAr: service.requirementsAr?.[index] || title,
    fees: service.fees,
    processingTime: service.processingTime,
    requirements: [t("willAddLater")],
    validation: { gender: "Any", nationality: "All nationalities", age: "Not specified yet", notes: "No validation restriction confirmed yet." }
  }));
}

function selectedSubService(service) {
  const subServices = getSubServices(service);
  return subServices.find(item => item.id === state.selectedSubServiceId) || subServices[0] || null;
}

function validationText(subService, field) {
  const validation = isArabic() ? subService?.validationAr || subService?.validation : subService?.validation;
  return validation?.[field] || t("willAddLater");
}

function validationNoteBullets(subServiceOrNotes) {
  const notes = typeof subServiceOrNotes === "string" ? subServiceOrNotes : validationText(subServiceOrNotes, "notes");
  return String(notes || "")
    .replace(/•/g, "\n")
    .split(/\n+|(?<=\.)\s+(?=[A-Z0-9]|For |The |A |Valid |Passport |ت|ي|ل|و|ف)/)
    .map(item => item.trim().replace(/^[-–•]\s*/, ""))
    .filter(Boolean);
}

function renderValidationNotes(subService) {
  const bullets = validationNoteBullets(subService);
  if (!bullets.length) return '<p>' + escapeHtml(t("notAdded")) + '</p>';
  return '<ul class="validation-note-list">' + bullets.map(item => '<li>' + escapeHtml(item) + '</li>').join("") + '</ul>';
}

function listRuleIncludes(rule, value) {
  const normalizedValue = normalize(value);
  if (!normalizedValue) return false;
  if (Array.isArray(rule)) return rule.some(item => normalize(item) === normalizedValue);
  return normalize(rule).split(/[,;/]/).map(item => item.trim()).includes(normalizedValue);
}

function eligibilityResult(subService) {
  const validation = subService?.validation || {};
  const selectedGender = els.genderFilter.value;
  const selectedNationality = els.nationalityFilter.value;
  const hasInput = Boolean(selectedGender || selectedNationality);
  const reasons = [];

  if (selectedGender) {
    const allowedGender = normalize(validation.gender || "Any");
    if (allowedGender && allowedGender !== "any" && allowedGender !== normalize(selectedGender)) {
      reasons.push(t("gender") + ": " + validation.gender);
    }
  }

  if (selectedNationality) {
    if (listRuleIncludes(validation.disallowedNationalities, selectedNationality)) {
      reasons.push(t("nationality") + ": " + selectedNationality);
    }
    if (validation.allowedNationalities && !listRuleIncludes(validation.allowedNationalities, selectedNationality)) {
      reasons.push(t("nationality") + ": " + validation.allowedNationalities);
    }
    const nationalityRule = normalize(validation.nationality || "All nationalities");
    if (!validation.allowedNationalities && nationalityRule && nationalityRule !== "all nationalities" && !nationalityRule.includes(normalize(selectedNationality))) {
      reasons.push(t("nationality") + ": " + validation.nationality);
    }
  }

  return { checked: hasInput, eligible: reasons.length === 0, reasons };
}

function categoryLabel(category) {
  if (!isArabic()) return category;
  return state.categoriesAr?.[category] || window.AKB_STATIC_DB?.categoriesAr?.[category] || category;
}

