function listItems(items, ordered = false) {
  const tag = ordered ? "ol" : "ul";
  if (!items?.length) return `<p>${t("notAdded")}</p>`;
  return `<${tag}>${items.map(item => `<li>${escapeHtml(item)}</li>`).join("")}</${tag}>`;
}
function feeSelectionKey(subService) {
  return subService?.id || "";
}

function selectedFeeIndexes(subService) {
  return state.selectedFeeItems[feeSelectionKey(subService)] || [];
}

function parseFeeAmount(amount) {
  const text = String(amount || "");
  if (/not included|reference only/i.test(text)) return 0;
  const match = text.replace(/,/g, "").match(/(?:AED|درهم)?\s*([0-9]+(?:\.[0-9]+)?)/i);
  return match ? Number(match[1]) : 0;
}

function feeItemName(item) {
  if (isArabic()) return item.labelAr || item.nameAr || item.name || item.label || t("fees");
  return item.name || item.label || item.nameAr || item.labelAr || t("fees");
}

function feeItemAmount(item) {
  return typeof item.amount === "number" ? formatAed(item.amount) : item.amount;
}

function formatAed(value) {
  return `AED ${value.toLocaleString("en-US", { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`;
}

function renderFeeMatrix(matrix) {
  const columns = matrix?.columns || [];
  const rows = matrix?.rows || [];
  if (!columns.length || !rows.length) return "";
  const typeLabel = isArabic() ? "النوع" : "Type";
  return `
    <div class="fee-matrix-scroll" role="region" aria-label="Domestic Worker fee table" tabindex="0">
      <div class="fee-service-grid" style="grid-template-columns: minmax(150px, 1.15fr) repeat(${columns.length}, minmax(112px, 0.85fr));">
        <div class="fee-service-cell fee-service-head">${escapeHtml(typeLabel)}</div>
        ${columns.map(column => `<div class="fee-service-cell fee-service-head">${escapeHtml(isArabic() ? column.labelAr || column.label : column.label || column.labelAr)}</div>`).join("")}
        ${rows.map(row => `
          <div class="fee-service-cell fee-service-row-title">${escapeHtml(isArabic() ? row.labelAr || row.label : row.label || row.labelAr)}</div>
          ${columns.map(column => `<div class="fee-service-cell">${escapeHtml(row.values?.[column.key] || "-")}</div>`).join("")}
        `).join("")}
      </div>
    </div>
  `;
}
function renderFeeItems(subService) {
  if (subService?.feeMatrix) {
    const note = subServiceText(subService, "fees");
    return `
      ${note ? `<div class="fee-note">${escapeHtml(note)}</div>` : ""}
      ${renderFeeMatrix(subService.feeMatrix)}
    `;
  }
  const items = subService?.feeItems || [];
  if (!items.length) return escapeHtml(subServiceText(subService, "fees") || t("willAddLater"));
  const selectedIndexes = selectedFeeIndexes(subService);
  const selectedItems = items.filter((item, index) => selectedIndexes.includes(index));
  const total = selectedItems.reduce((sum, item) => sum + parseFeeAmount(item.amount), 0);
  const selectedSummary = selectedItems.length
    ? selectedItems.map(item => `<span>${escapeHtml(feeItemName(item))} - ${escapeHtml(feeItemAmount(item))}</span>`).join("")
    : `<span>${t("noFeesSelected")}</span>`;

  return `
    <div class="fee-note">${escapeHtml(subServiceText(subService, "fees") || t("finalFeeDepends"))}</div>
    <div class="fee-item-list">
      ${items.map((item, index) => {
        const isReference = /reference only/i.test(String(item.tax || "")) || /full quote reference/i.test(String(feeItemName(item) || ""));
        const isSelected = selectedIndexes.includes(index);
        return `
          <button class="fee-item ${isSelected ? "selected" : ""} ${isReference ? "reference" : ""}" type="button" data-fee-index="${index}" aria-pressed="${isSelected}">
            <strong>${escapeHtml(feeItemName(item))}</strong>
            <span>${escapeHtml(feeItemAmount(item))}</span>
            ${item.tax ? `<small>${escapeHtml(item.tax)}</small>` : ""}
            ${item.appliesWhen ? `<em>${escapeHtml(t("appliesWhen"))}: ${escapeHtml(item.appliesWhen)}</em>` : ""}
          </button>
        `;
      }).join("")}
    </div>
    <div class="fee-total-box">
      <div>
        <strong>${t("selectedFees")}</strong>
        <div class="selected-fee-list">${selectedSummary}</div>
      </div>
      <div class="fee-total">
        <span>${t("selectedTotal")}</span>
        <strong>${formatAed(total)}</strong>
      </div>
    </div>
  `;
}

function cleanExportLine(value) {
  return String(value || "").replace(/\r?\n/g, " ").trim();
}

function exportSection(title, value) {
  const items = Array.isArray(value) ? value : [value];
  return { title, lines: items.map(item => cleanExportLine(item)).filter(Boolean) };
}

function serviceExportFilename(service, subService) {
  const rawName = [service?.title, subService?.title].filter(Boolean).join(" - ") || "AKB Service";
  const safeName = rawName.toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/^-|-$/g, "").slice(0, 90) || "akb-service";
  return "AKB-" + safeName + "-" + new Date().toISOString().slice(0, 10) + ".pdf";
}

function selectedFeeExportLines(subService) {
  if (subService?.feeMatrix) {
    const columns = subService.feeMatrix.columns || [];
    return (subService.feeMatrix.rows || []).map(row => {
      const cells = columns.map(column => `${column.label || column.labelAr}: ${row.values?.[column.key] || "-"}`);
      return `${row.label || row.labelAr}: ${cells.join(" | ")}`;
    });
  }
  const items = subService?.feeItems || [];
  if (!items.length) return [subServiceText(subService, "fees") || t("willAddLater")];
  const selectedIndexes = selectedFeeIndexes(subService);
  const selectedItems = items.filter((item, index) => selectedIndexes.includes(index));
  const feeLines = items.map((item, index) => {
    const details = [];
    if (selectedIndexes.includes(index)) details.push("selected");
    if (item.appliesWhen) details.push(t("appliesWhen") + ": " + item.appliesWhen);
    if (item.tax) details.push(item.tax);
    return feeItemName(item) + ": " + feeItemAmount(item) + (details.length ? " | " + details.join(" | ") : "");
  });
  const total = selectedItems.reduce((sum, item) => sum + parseFeeAmount(item.amount), 0);
  return [...feeLines, t("selectedTotal") + ": " + formatAed(total)];
}

function buildServiceExportSections(service, subService) {
  const validation = isArabic() ? subService?.validationAr || subService?.validation : subService?.validation;
  return [
    exportSection(t("services"), serviceText(service, "title")),
    exportSection(t("exactService"), subServiceText(subService, "title")),
    exportSection("Category", categoryLabel(service.category)),
    exportSection("Department", visibleDepartment(service) || t("notAdded")),
    exportSection(t("updated"), service.updatedAt ? new Date(service.updatedAt).toLocaleDateString() : t("notAdded")),
    exportSection("Summary", subServiceText(subService, "summary") || serviceText(service, "summary")),
    exportSection(t("processingTime"), subServiceText(subService, "processingTime") || serviceText(service, "processingTime")),
    exportSection(t("escalation"), serviceText(service, "escalationContact") || t("notAdded")),
    exportSection(t("fees"), selectedFeeExportLines(subService)),
    exportSection(t("validation"), [
      t("gender") + ": " + (validation?.gender || t("notAdded")),
      t("nationality") + ": " + (validation?.nationality || t("notAdded")),
      t("age") + ": " + (validation?.age || t("notAdded"))
    ]),
    exportSection(t("validationNotes"), validationNoteBullets(validation?.notes || t("notAdded"))),
    exportSection(t("namesUnder"), subServiceListItems(subService, "requirements")),
    exportSection(t("employeeSteps"), subServiceListItems(subService, "steps")),
    exportSection(t("callCenterScript"), subServiceText(subService, "callCenterScript") || serviceText(service, "callCenterScript")),
    exportSection(t("internalNotes"), subServiceText(subService, "internalNotes") || serviceText(service, "internalNotes"))
  ];
}

function wrapCanvasText(ctx, text, maxWidth) {
  const words = String(text || "").split(/\s+/).filter(Boolean);
  const lines = [];
  let line = "";
  for (const word of words) {
    const test = line ? line + " " + word : word;
    if (ctx.measureText(test).width <= maxWidth || !line) line = test;
    else { lines.push(line); line = word; }
  }
  if (line) lines.push(line);
  return lines.length ? lines : [""];
}

function loadAamerLogo() {
  if (!aamerLogoPromise) {
    aamerLogoPromise = new Promise(resolve => {
      const image = new Image();
      image.onload = () => {
        aamerLogoImage = image;
        resolve(image);
      };
      image.onerror = () => resolve(null);
      image.src = AAMER_LOGO_SRC;
    });
  }
  return aamerLogoPromise;
}

function drawImageContain(ctx, image, x, y, width, height, alpha = 1) {
  if (!image) return;
  const ratio = Math.min(width / image.naturalWidth, height / image.naturalHeight);
  const drawWidth = image.naturalWidth * ratio;
  const drawHeight = image.naturalHeight * ratio;
  ctx.save();
  ctx.globalAlpha = alpha;
  ctx.drawImage(image, x + (width - drawWidth) / 2, y + (height - drawHeight) / 2, drawWidth, drawHeight);
  ctx.restore();
}


function drawPdfChrome(ctx, pageNumber, pageCount, width, height, logoImage) {
  ctx.fillStyle = "#ffffff";
  ctx.fillRect(0, 0, width, height);
  if (logoImage) {
    ctx.save();
    ctx.translate(width / 2, height / 2);
    ctx.rotate(-Math.PI / 8);
    drawImageContain(ctx, logoImage, -315, -345, 630, 690, 0.075);
    ctx.restore();
  } else {
    ctx.save();
    ctx.translate(width / 2, height / 2);
    ctx.rotate(-Math.PI / 7);
    ctx.globalAlpha = 0.055;
    ctx.fillStyle = "#0b1f3a";
    ctx.font = "900 178px Arial";
    ctx.textAlign = "center";
    ctx.fillText("AAMER", 0, -18);
    ctx.font = "900 120px Arial";
    ctx.fillStyle = "#c92132";
    ctx.fillText("AKB", 0, 118);
    ctx.restore();
  }
  ctx.fillStyle = "#0b1f3a";
  ctx.fillRect(0, 0, width, 96);
  ctx.fillStyle = "#c92132";
  ctx.fillRect(0, 96, width, 8);
  if (logoImage) {
    drawImageContain(ctx, logoImage, 42, 16, 118, 70, 1);
    ctx.fillStyle = "#ffffff";
    ctx.font = "700 17px Arial";
    ctx.textAlign = "left";
    ctx.fillText("Internal Knowledge Base", 174, 56);
  } else {
    ctx.fillStyle = "#ffffff";
    ctx.font = "800 30px Arial";
    ctx.textAlign = "left";
    ctx.fillText("AAMER", 54, 42);
    ctx.font = "700 17px Arial";
    ctx.fillText("Internal Knowledge Base", 54, 70);
  }
  ctx.textAlign = "right";
  ctx.font = "700 14px Arial";
  ctx.fillText("AKB Service Export", width - 54, 42);
  ctx.fillText(new Date().toLocaleDateString(), width - 54, 70);
  ctx.fillStyle = "#0b1f3a";
  ctx.fillRect(0, height - 70, width, 70);
  ctx.fillStyle = "#ffffff";
  ctx.font = "600 12px Arial";
  ctx.textAlign = "left";
  ctx.fillText("Aamer Knowledge Base | Internal company document | For employees and call center only", 54, height - 42);
  ctx.fillStyle = "#f5f5f5";
  ctx.fillText("Generated by AKB. Verify sensitive customer cases with the assigned escalation contact before submission.", 54, height - 22);
  ctx.textAlign = "right";
  ctx.fillText(pageNumber + " / " + pageCount, width - 54, height - 32);
  ctx.textAlign = "left";
}

function makePdfPages(service, subService, logoImage) {
  const width = 1240, height = 1754, marginX = 74, topY = 138, bottomY = height - 104;
  const maxWidth = width - marginX * 2;
  const sections = buildServiceExportSections(service, subService);
  const pages = [];
  let canvas = document.createElement("canvas");
  canvas.width = width; canvas.height = height;
  let ctx = canvas.getContext("2d");
  let y = topY;
  const newPage = () => { pages.push(canvas); canvas = document.createElement("canvas"); canvas.width = width; canvas.height = height; ctx = canvas.getContext("2d"); y = topY; };
  const ensureSpace = needed => { if (y + needed > bottomY) newPage(); };
  const drawWrapped = (text, options = {}) => {
    ctx.font = options.font || "400 24px Arial";
    const lines = wrapCanvasText(ctx, text, maxWidth - (options.indent || 0));
    const lineHeight = options.lineHeight || 34;
    ensureSpace(lines.length * lineHeight + 10);
    ctx.fillStyle = options.color || "#17211f";
    for (const line of lines) { ctx.fillText(line, marginX + (options.indent || 0), y); y += lineHeight; }
  };
  drawWrapped(subServiceText(subService, "title") || serviceText(service, "title"), { font: "800 38px Arial", color: "#0b1f3a", lineHeight: 48 });
  drawWrapped("AKB - Aamer Knowledge Base", { font: "700 22px Arial", color: "#c92132", lineHeight: 32 });
  y += 18;
  for (const section of sections) {
    if (!section.lines.length) section.lines = [t("notAdded")];
    ensureSpace(96);
    ctx.fillStyle = "#eef2f7"; ctx.fillRect(marginX, y - 28, maxWidth, 44);
    ctx.fillStyle = "#c92132"; ctx.fillRect(marginX, y - 28, 8, 44);
    drawWrapped(section.title, { font: "800 22px Arial", color: "#0b1f3a", lineHeight: 32, indent: 18 });
    y += 8;
    for (const line of section.lines) drawWrapped((section.lines.length > 1 ? "- " : "") + line, { font: "400 21px Arial", color: "#17211f", lineHeight: 31, indent: 18 });
    y += 18;
  }
  pages.push(canvas);
  return pages.map((page, index) => {
    const finalCanvas = document.createElement("canvas");
    finalCanvas.width = width; finalCanvas.height = height;
    const finalCtx = finalCanvas.getContext("2d");
    drawPdfChrome(finalCtx, index + 1, pages.length, width, height, logoImage);
    finalCtx.drawImage(page, 0, 0);
    return finalCanvas;
  });
}

function canvasesToPdfBlob(canvases, title) {
  const pageW = 595.28, pageH = 841.89;
  const objects = [], imageNums = [], pageNums = [];
  for (const canvas of canvases) {
    const imageData = atob(canvas.toDataURL("image/jpeg", 0.9).split(",")[1]);
    imageNums.push(objects.length + 1);
    objects.push("<< /Type /XObject /Subtype /Image /Width " + canvas.width + " /Height " + canvas.height + " /ColorSpace /DeviceRGB /BitsPerComponent 8 /Filter /DCTDecode /Length " + imageData.length + " >>\nstream\n" + imageData + "\nendstream");
  }
  for (let i = 0; i < canvases.length; i += 1) {
    const content = "q\n" + pageW + " 0 0 " + pageH + " 0 0 cm\n/Im" + (i + 1) + " Do\nQ";
    const contentObj = objects.length + 1;
    objects.push("<< /Length " + content.length + " >>\nstream\n" + content + "\nendstream");
    const pageObj = objects.length + 1;
    pageNums.push(pageObj);
    objects.push("<< /Type /Page /Parent PAGES_REF 0 R /MediaBox [0 0 " + pageW + " " + pageH + "] /Resources << /XObject << /Im" + (i + 1) + " " + imageNums[i] + " 0 R >> >> /Contents " + contentObj + " 0 R >>");
  }
  const pagesObj = objects.length + 1;
  objects.push("<< /Type /Pages /Kids [" + pageNums.map(num => num + " 0 R").join(" ") + "] /Count " + pageNums.length + " >>");
  const catalogObj = objects.length + 1;
  objects.push("<< /Type /Catalog /Pages " + pagesObj + " 0 R >>");
  const infoObj = objects.length + 1;
  objects.push("<< /Title (" + String(title || "AKB Service Export").replace(/[()\\]/g, "\\$&") + ") /Creator (AKB Aamer Knowledge Base) >>");
  for (let i = 0; i < objects.length; i += 1) objects[i] = objects[i].replaceAll("PAGES_REF", String(pagesObj));
  let pdf = "%PDF-1.4\n%\xE2\xE3\xCF\xD3\n";
  const offsets = [0];
  objects.forEach((object, index) => { offsets.push(pdf.length); pdf += (index + 1) + " 0 obj\n" + object + "\nendobj\n"; });
  const xref = pdf.length;
  pdf += "xref\n0 " + (objects.length + 1) + "\n0000000000 65535 f \n";
  offsets.slice(1).forEach(offset => { pdf += String(offset).padStart(10, "0") + " 00000 n \n"; });
  pdf += "trailer\n<< /Size " + (objects.length + 1) + " /Root " + catalogObj + " 0 R /Info " + infoObj + " 0 R >>\nstartxref\n" + xref + "\n%%EOF";
  const bytes = new Uint8Array(pdf.length);
  for (let i = 0; i < pdf.length; i += 1) bytes[i] = pdf.charCodeAt(i) & 0xff;
  return new Blob([bytes], { type: "application/pdf" });
}

async function downloadServiceFile(service, subService) {
  const params = new URLSearchParams();
  if (subService?.id) params.set("subService", subService.id);
  const response = await fetch(`${API_BASE}/api/services/${encodeURIComponent(service.id)}/export?${params.toString()}`);
  if (!response.ok) {
    let message = "Export request failed";
    try {
      const data = await response.json();
      message = data.error || message;
    } catch (error) {}
    throw new Error(message);
  }
  const blob = await response.blob();
  const disposition = response.headers.get("Content-Disposition") || "";
  const match = disposition.match(/filename="?([^";]+)"?/i);
  const filename = match?.[1] || serviceExportFilename(service, subService);
  const url = URL.createObjectURL(blob);
  const link = document.createElement("a");
  link.href = url;
  link.download = filename;
  link.rel = "noopener";
  link.style.display = "none";
  document.body.appendChild(link);
  link.click();
  window.setTimeout(() => link.remove(), 1000);
  return { url, filename, size: blob.size };
}

